import anthropic
from dataclasses import dataclass

@dataclass
class ContextualisedChunk:
    original_text: str
    context:       str
    combined_text: str   # context + original, ready for indexing

def contextualise_document_chunks(
    full_document: str,
    chunks: list[str],
    model: str = "claude-haiku-4-5-20251001",
) -> list[ContextualisedChunk]:
    """
    Generate context for all chunks in a document, reusing the cached
    document prefix across all chunks via Anthropic's prompt caching.
    """
    client = anthropic.Anthropic()
    results = []

    for chunk_text in chunks:
        response = client.messages.create(
            model=model,
            max_tokens=200,
            system=[
                {
                    "type": "text",
                    "text": (
                        "You generate short retrieval contexts for document chunks. "
                        "Reply with 1–3 sentences only."
                    ),
                    "cache_control": {"type": "ephemeral"},   # cache the system prompt
                }
            ],
            messages=[
                {
                    "role": "user",
                    "content": [
                        {
                            "type": "text",
                            "text": f"<document>\n{full_document}\n</document>\n",
                            "cache_control": {"type": "ephemeral"},   # cache the document
                        },
                        {
                            "type": "text",
                            "text": (
                                f"Situate this chunk for retrieval (1–3 sentences):\n"
                                f"<chunk>\n{chunk_text}\n</chunk>"
                            ),
                        },
                    ],
                }
            ],
        )
        context = response.content[0].text.strip()
        results.append(ContextualisedChunk(
            original_text=chunk_text,
            context=context,
            combined_text=f"{context}\n\n{chunk_text}",
        ))
    return results
